h=open('web/templates/tuner.html').read()
h=h.replace(
"['c3b','c3d','c3m'].forEach(function(cid){\n    var el=document.getElementById(cid);if(!el)return;\n    var key=cid==='c3b'?'base':cid==='c3d'?'delta':'mod';\n    function rs(){var r=el.getBoundingClientRect();el.width=r.width||300;el.height=r.height||250;drawAll()}\n    el.addEventListener(\"mousedown\",function(e){C3[key].drag=true;C3[key].lx=e.clientX})\n    el.addEventListener(\"touchstart\",function(e){C3[key].drag=true;C3[key].lx=e.touches[0].clientX},{passive:true})\n    rs();\n  });\n  window.addEventListener('resize',function(){\n    ['c3b','c3d','c3m'].forEach(function(cid){\n      var el=document.getElementById(cid);if(!el)return;\n      el.width=el.parentElement.clientWidth||300;\n      el.height=el.parentElement.clientHeight||250;\n    });\n    drawAll();\n  });",
"var el=document.getElementById('c3all');if(!el)return;\n  function rs(){el.width=el.parentElement.clientWidth||900;el.height=el.parentElement.clientHeight||300;drawAll()}\n  el.addEventListener('mousedown',function(e){for(var k in C3){C3[k].drag=true;C3[k].lx=e.clientX}});\n  el.addEventListener('touchstart',function(e){for(var k in C3){C3[k].drag=true;C3[k].lx=e.touches[0].clientX}},{passive:true});\n  rs();\n  window.addEventListener('resize',rs);")
open('web/templates/tuner.html','w').write(h)
